import puppeteer from 'puppeteer';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

(async () => {
    try {
        console.log("Launching Puppeteer...");
        const browser = await puppeteer.launch();
        const page = await browser.newPage();
        
        const filesToConvert = [
            {
                input: path.join(__dirname, 'public', 'Jeno_Aldrei_Laurente_CV.html'),
                output: path.join(__dirname, 'public', 'Jeno_Aldrei_Laurente_Technical_CV.pdf')
            },
            {
                input: path.join(__dirname, 'public', 'Jeno_Aldrei_Laurente_General_CV.html'),
                output: path.join(__dirname, 'public', 'Jeno_Aldrei_Laurente_General_CV.pdf')
            }
        ];

        for (const file of filesToConvert) {
            console.log(`Converting ${path.basename(file.input)} to PDF...`);
            // We use file:// protocol to load the local html files
            await page.goto(`file://${file.input}`, { waitUntil: 'networkidle0' });
            
            // Generate PDF from the page
            await page.pdf({
                path: file.output,
                format: 'A4',
                printBackground: true,
                margin: { top: '0', right: '0', bottom: '0', left: '0' }
            });
            console.log(`Successfully created ${path.basename(file.output)}`);
        }

        await browser.close();
        console.log("PDF generation complete.");
    } catch (error) {
        console.error("Error generating PDFs:", error);
        process.exit(1);
    }
})();

import { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import Navbar from './components/layout/Navbar';
import Hero from './components/sections/Hero';
import About from './components/sections/About';
import Hobbies from './components/sections/Hobbies';
import Skills from './components/sections/Skills';
import Projects from './components/sections/Projects';
import Journey from './components/sections/Journey';
import Contact from './components/sections/Contact';
import Footer from './components/layout/Footer';
import ParticleBackground from './components/ui/ParticleBackground';
import ScrollProgress from './components/ui/ScrollProgress';
import './styles/components.css';

function App() {
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    // Simulate loading time for assets
    const timer = setTimeout(() => {
      setIsLoading(false);
    }, 2000);

    return () => clearTimeout(timer);
  }, []);

  return (
    <>
      <AnimatePresence mode="wait">
        {isLoading ? (
          <motion.div
            key="loading"
            className="loading-screen"
            initial={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            transition={{ duration: 0.5 }}
          >
            <motion.div
              className="loading-logo"
              initial={{ scale: 0.8, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              transition={{
                duration: 0.5,
                repeat: Infinity,
                repeatType: "reverse"
              }}
            >
              JA
            </motion.div>
          </motion.div>
        ) : (
          <motion.div
            key="app"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ duration: 0.5 }}
          >
            {/* Background Effects */}
            <div className="bg-grid" />
            <ParticleBackground />

            {/* Scroll Progress Indicator */}
            <ScrollProgress />

            {/* Navigation */}
            <Navbar />

            {/* Main Content */}
            <main>
              <Hero />
              <Projects />
              <Skills />
              <About />
              <Hobbies />
              <Journey />
              <Contact />
            </main>

            {/* Footer */}
            <Footer />
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
}

export default App;

import { useState, useEffect, useRef } from 'react';
import { motion } from 'framer-motion';
import { Home, User, Code, Mail, Menu, X, Download, ChevronDown } from 'lucide-react';
import { profileData } from '../../data/portfolioData';
import { CVOptions, openCVInNewTab } from '../../utils/cvService';

const navItems = [
    { name: 'Home', href: '#home', icon: Home },
    { name: 'About', href: '#about', icon: User },
    { name: 'Projects', href: '#projects', icon: Code },
    { name: 'Contact', href: '#contact', icon: Mail },
];

const Navbar = () => {
    const [isScrolled, setIsScrolled] = useState(false);
    const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
    const [activeSection, setActiveSection] = useState('home');
    const [isCVDropdownOpen, setIsCVDropdownOpen] = useState(false);
    const cvDropdownRef = useRef(null);

    useEffect(() => {
        const handleScroll = () => {
            setIsScrolled(window.scrollY > 100);

            // Update active section based on scroll position
            const sections = navItems.map(item => item.href.substring(1));
            for (const section of sections.reverse()) {
                const element = document.getElementById(section);
                if (element) {
                    const rect = element.getBoundingClientRect();
                    if (rect.top <= 200) {
                        setActiveSection(section);
                        break;
                    }
                }
            }
        };

        window.addEventListener('scroll', handleScroll);
        return () => window.removeEventListener('scroll', handleScroll);
    }, []);

    // Close CV dropdown when clicking outside
    useEffect(() => {
        const handleClickOutside = (event) => {
            if (cvDropdownRef.current && !cvDropdownRef.current.contains(event.target)) {
                setIsCVDropdownOpen(false);
            }
        };

        if (isCVDropdownOpen) {
            document.addEventListener('mousedown', handleClickOutside);
        }
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, [isCVDropdownOpen]);

    const handleNavClick = (e, href) => {
        e.preventDefault();
        const target = document.querySelector(href);
        if (target) {
            target.scrollIntoView({ behavior: 'smooth' });
        }
        setIsMobileMenuOpen(false);
    };

    const handleCVSelect = (cvType) => {
        openCVInNewTab(cvType);
        setIsCVDropdownOpen(false);
    };

    return (
        <>
            <motion.nav
                className={`navbar ${isScrolled ? 'scrolled' : ''}`}
                initial={{ y: -100 }}
                animate={{ y: 0 }}
                transition={{ duration: 0.5 }}
            >
                <div className="navbar-container">
                    {/* Logo */}
                    <a href="#home" className="navbar-logo" onClick={(e) => handleNavClick(e, '#home')}>
                        <div className="logo-icon">{profileData.initials}</div>
                        <div className="logo-text">
                            <div className="logo-name">{profileData.nickname}</div>
                            <div className="logo-title">Full Stack Dev</div>
                        </div>
                    </a>

                    {/* Desktop Navigation */}
                    <ul className="navbar-links">
                        {navItems.map((item) => (
                            <li key={item.name}>
                                <a
                                    href={item.href}
                                    className={activeSection === item.href.substring(1) ? 'active' : ''}
                                    onClick={(e) => handleNavClick(e, item.href)}
                                >
                                    <item.icon size={18} />
                                    {item.name}
                                </a>
                            </li>
                        ))}
                    </ul>

                    {/* Download CV Dropdown */}
                    <div className="cv-dropdown" ref={cvDropdownRef}>
                        <button 
                            className="cv-download-btn"
                            onClick={() => setIsCVDropdownOpen(!isCVDropdownOpen)}
                        >
                            <Download size={18} />
                            <span>Download CV</span>
                            <ChevronDown size={16} className={`dropdown-icon ${isCVDropdownOpen ? 'open' : ''}`} />
                        </button>

                        {isCVDropdownOpen && (
                            <motion.div 
                                className="cv-dropdown-menu"
                                initial={{ opacity: 0, y: -10 }}
                                animate={{ opacity: 1, y: 0 }}
                                exit={{ opacity: 0, y: -10 }}
                                transition={{ duration: 0.2 }}
                            >
                                <button 
                                    className="cv-dropdown-item"
                                    onClick={() => handleCVSelect('TECHNICAL')}
                                >
                                    <span>Technical CV</span>
                                </button>
                                <button 
                                    className="cv-dropdown-item"
                                    onClick={() => handleCVSelect('GENERAL')}
                                >
                                    <span>General CV</span>
                                </button>
                            </motion.div>
                        )}
                    </div>

                    {/* Mobile Toggle */}
                    <button
                        className="mobile-toggle"
                        onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
                        aria-label="Toggle menu"
                    >
                        {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
                    </button>
                </div>
            </motion.nav>

            {/* Mobile Menu */}
            <div className={`mobile-menu ${isMobileMenuOpen ? 'active' : ''}`}>
                <ul className="mobile-menu-links">
                    {navItems.map((item, index) => (
                        <motion.li
                            key={item.name}
                            initial={{ opacity: 0, y: 20 }}
                            animate={isMobileMenuOpen ? { opacity: 1, y: 0 } : { opacity: 0, y: 20 }}
                            transition={{ delay: index * 0.1 }}
                        >
                            <a href={item.href} onClick={(e) => handleNavClick(e, item.href)}>
                                <item.icon size={24} />
                                {item.name}
                            </a>
                        </motion.li>
                    ))}
                    {/* Mobile Download CV Dropdown */}
                    <motion.li
                        initial={{ opacity: 0, y: 20 }}
                        animate={isMobileMenuOpen ? { opacity: 1, y: 0 } : { opacity: 0, y: 20 }}
                        transition={{ delay: navItems.length * 0.1 }}
                    >
                        <div className="mobile-cv-menu">
                            <button 
                                className="mobile-cv-btn"
                                onClick={() => setIsCVDropdownOpen(!isCVDropdownOpen)}
                            >
                                <Download size={24} />
                                Download CV
                                <ChevronDown size={18} className={`dropdown-icon ${isCVDropdownOpen ? 'open' : ''}`} />
                            </button>
                            {isCVDropdownOpen && (
                                <motion.div 
                                    className="mobile-cv-dropdown-menu"
                                    initial={{ opacity: 0, height: 0 }}
                                    animate={{ opacity: 1, height: 'auto' }}
                                    exit={{ opacity: 0, height: 0 }}
                                    transition={{ duration: 0.2 }}
                                >
                                    <button 
                                        className="mobile-cv-dropdown-item"
                                        onClick={() => handleCVSelect('TECHNICAL')}
                                    >
                                        <span>Technical CV</span>
                                        <span className="cv-description">For Tech Roles</span>
                                    </button>
                                    <button 
                                        className="mobile-cv-dropdown-item"
                                        onClick={() => handleCVSelect('GENERAL')}
                                    >
                                        <span>General CV</span>
                                        <span className="cv-description">For Call Center / Teaching</span>
                                    </button>
                                </motion.div>
                            )}
                        </div>
                    </motion.li>
                </ul>
            </div>
        </>
    );
};

export default Navbar;

import { motion } from 'framer-motion';
import { useRef } from 'react';
import { Code, Server, Smartphone, Palette, User } from 'lucide-react';
import { profileData, expertiseData } from '../../data/portfolioData';

const iconMap = {
    code: Code,
    server: Server,
    smartphone: Smartphone,
    palette: Palette
};

const About = () => {
    const ref = useRef(null);

    const containerVariants = {
        hidden: { opacity: 0 },
        visible: {
            opacity: 1,
            transition: { staggerChildren: 0.15 }
        }
    };

    const itemVariants = {
        hidden: { opacity: 0, y: 40 },
        visible: {
            opacity: 1,
            y: 0,
            transition: { duration: 0.6, ease: 'easeOut' }
        }
    };

    return (
        <section id="about" className="about" ref={ref}>
            <div className="container">
                {/* Section Header with scroll animation */}
                <motion.div
                    className="section-header"
                    initial={{ opacity: 0, y: 40 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true, margin: "-100px" }}
                    transition={{ duration: 0.6 }}
                >
                    <span className="section-tag">
                        <User size={14} />
                        About Me
                    </span>
                    <h2 className="section-title">Know Who I Am</h2>
                    <p className="section-subtitle">
                        Passionate developer with expertise in creating innovative digital solutions
                    </p>
                </motion.div>

                {/* About Content with scroll animation */}
                <motion.div
                    className="about-grid"
                    variants={containerVariants}
                    initial="hidden"
                    whileInView="visible"
                    viewport={{ once: true, margin: "-50px" }}
                >
                    {/* Left Column - Intro */}
                    <motion.div className="about-intro" variants={itemVariants}>
                        <h3>Building the Future, One Line of Code at a Time</h3>
                        <p>
                            I'm a passionate Full Stack Developer and UI/UX Designer creating innovative digital
                            solutions. My journey in technology started with a curiosity about how things work,
                            and it has evolved into a deep passion for crafting exceptional user experiences.
                        </p>
                        <p>
                            I believe in the power of clean code, thoughtful design, and user-centered development.
                            Whether it's building scalable web applications, mobile apps, or leveraging no-code
                            automation tools like GoHighLevel for business workflows ΓÇö every project is an
                            opportunity to push boundaries and create something remarkable.
                        </p>

                        {/* Startup Highlight */}
                        <motion.div
                            className="startup-highlight"
                            initial={{ opacity: 0, scale: 0.95 }}
                            whileInView={{ opacity: 1, scale: 1 }}
                            viewport={{ once: true }}
                            transition={{ delay: 0.3, duration: 0.5 }}
                        >
                            <div className="highlight-badge">≡ƒÜÇ Startup Founder</div>
                            <h4>Selected by Naga City Government</h4>
                            <p>
                                Our team was recognized and selected as Startup Founders for <strong>Digistall</strong> ΓÇö
                                a comprehensive leasehold management system now deployed and serving real users.
                            </p>
                        </motion.div>
                    </motion.div>

                    {/* Right Column - Top 2 Expertise Cards */}
                    <div className="about-cards">
                        {expertiseData.slice(0, 2).map((item, index) => {
                            const IconComponent = iconMap[item.icon];
                            return (
                                <motion.div
                                    key={item.title}
                                    className="about-card"
                                    initial={{ opacity: 0, x: 40 }}
                                    whileInView={{ opacity: 1, x: 0 }}
                                    viewport={{ once: true, margin: "-50px" }}
                                    transition={{ delay: index * 0.1, duration: 0.5 }}
                                    whileHover={{ x: 10 }}
                                >
                                    <div className="about-card-header">
                                        <div className="about-card-icon">
                                            <IconComponent size={24} />
                                        </div>
                                        <h4>{item.title}</h4>
                                    </div>
                                    <p>{item.description}</p>
                                    <div className="tech-tags">
                                        {item.technologies.map((tech) => (
                                            <span key={tech} className="tech-tag">
                                                {tech}
                                            </span>
                                        ))}
                                    </div>
                                </motion.div>
                            );
                        })}
                    </div>
                </motion.div>

                {/* Bottom - Remaining Expertise Cards (Mobile & UI/UX) */}
                <div className="about-bottom-grid">
                    {expertiseData.slice(2).map((item, index) => {
                        const IconComponent = iconMap[item.icon];
                        return (
                            <motion.div
                                key={item.title}
                                className="about-card"
                                initial={{ opacity: 0, y: 40 }}
                                whileInView={{ opacity: 1, y: 0 }}
                                viewport={{ once: true, margin: "-50px" }}
                                transition={{ delay: 0.2 + (index * 0.1), duration: 0.5 }}
                                whileHover={{ y: -5 }}
                            >
                                <div className="about-card-header">
                                    <div className="about-card-icon">
                                        <IconComponent size={24} />
                                    </div>
                                    <h4>{item.title}</h4>
                                </div>
                                <p>{item.description}</p>
                                <div className="tech-tags">
                                    {item.technologies.map((tech) => (
                                        <span key={tech} className="tech-tag">
                                            {tech}
                                        </span>
                                    ))}
                                </div>
                            </motion.div>
                        );
                    })}
                </div>
            </div>
        </section>
    );
};

export default About;

import { useState, useRef } from 'react';
import { motion, useInView } from 'framer-motion';
import {
    Mail,
    Phone,
    MapPin,
    Send,
    User,
    MessageSquare,
    Tag,
    Github,
    Linkedin,
    Facebook,
    CheckCircle,
    AlertCircle,
    Loader
} from 'lucide-react';
import { profileData } from '../../data/portfolioData';
import { sendEmail } from '../../utils/emailService';

const Contact = () => {
    const ref = useRef(null);
    const isInView = useInView(ref, { once: true, margin: '-100px' });

    const [formData, setFormData] = useState({
        name: '',
        email: '',
        subject: '',
        message: ''
    });
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [submitStatus, setSubmitStatus] = useState(null);

    const handleChange = (e) => {
        setFormData({
            ...formData,
            [e.target.name]: e.target.value
        });
    };

    const handleSubmit = async (e) => {
        e.preventDefault();
        setIsSubmitting(true);
        setSubmitStatus(null);

        try {
            await sendEmail(formData);
            setSubmitStatus({
                type: 'success',
                message: 'Thank you! Your message has been sent successfully. I\'ll get back to you soon!'
            });
            setFormData({ name: '', email: '', subject: '', message: '' });
        } catch (error) {
            setSubmitStatus({
                type: 'error',
                message: error.message || 'Sorry, there was an error sending your message. Please try again.'
            });
        } finally {
            setIsSubmitting(false);
        }
    };

    const containerVariants = {
        hidden: { opacity: 0 },
        visible: {
            opacity: 1,
            transition: {
                staggerChildren: 0.1
            }
        }
    };

    const itemVariants = {
        hidden: { opacity: 0, y: 20 },
        visible: {
            opacity: 1,
            y: 0,
            transition: { duration: 0.5 }
        }
    };

    const contactCards = [
        {
            icon: Mail,
            title: 'Email Me',
            info: profileData.email,
            link: `mailto:${profileData.email}`
        },
        {
            icon: Phone,
            title: 'Call Me',
            info: profileData.phone,
            link: `tel:${profileData.phone.replace(/\s/g, '')}`
        },
        {
            icon: MapPin,
            title: 'Location',
            info: profileData.location,
            link: null
        }
    ];

    const socialLinks = [
        { icon: Github, url: profileData.socialLinks.github, label: 'GitHub' },
        { icon: Linkedin, url: profileData.socialLinks.linkedin, label: 'LinkedIn' },
        { icon: Facebook, url: profileData.socialLinks.facebook, label: 'Facebook' },
        { icon: Send, url: profileData.socialLinks.telegram, label: 'Telegram' }
    ];

    return (
        <section id="contact" className="contact" ref={ref}>
            <div className="container">
                {/* Section Header */}
                <motion.div
                    className="section-header"
                    initial={{ opacity: 0, y: 40 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true, margin: "-100px" }}
                    transition={{ duration: 0.6 }}
                >
                    <span className="section-tag">
                        <Mail size={14} />
                        Get in Touch
                    </span>
                    <h2 className="section-title">Let's Connect</h2>
                    <p className="section-subtitle">
                        Ready to bring your ideas to life? Let's discuss your next project and create something amazing together.
                    </p>
                </motion.div>

                {/* Contact Grid */}
                <motion.div
                    className="contact-grid"
                    variants={containerVariants}
                    initial="hidden"
                    whileInView="visible"
                    viewport={{ once: true, margin: "-50px" }}
                >
                    {/* Contact Info */}
                    <motion.div className="contact-info" variants={itemVariants}>
                        <h3>Let's Work Together</h3>
                        <p>
                            I'm always excited to collaborate on new projects and ideas.
                            Whether you have a question or just want to say hello, feel free to reach out!
                        </p>

                        {/* Contact Cards */}
                        <div className="contact-cards">
                            {contactCards.map((card, index) => (
                                <motion.div
                                    key={card.title}
                                    className="contact-card"
                                    variants={itemVariants}
                                    whileHover={{ x: 10 }}
                                >
                                    <div className="contact-card-icon">
                                        <card.icon size={22} />
                                    </div>
                                    <div className="contact-card-content">
                                        <h4>{card.title}</h4>
                                        {card.link ? (
                                            <a href={card.link}>{card.info}</a>
                                        ) : (
                                            <p>{card.info}</p>
                                        )}
                                    </div>
                                </motion.div>
                            ))}
                        </div>

                        {/* Social Links */}
                        <div className="social-links">
                            {socialLinks.map((social) => (
                                <a
                                    key={social.label}
                                    href={social.url}
                                    target="_blank"
                                    rel="noopener noreferrer"
                                    className="social-link"
                                    aria-label={social.label}
                                >
                                    <social.icon size={20} />
                                </a>
                            ))}
                        </div>
                    </motion.div>

                    {/* Contact Form */}
                    <motion.div className="contact-form-container" variants={itemVariants}>
                        <div className="contact-form-header">
                            <h3>Send me a message</h3>
                            <p>Fill out the form below and I'll get back to you as soon as possible.</p>
                        </div>

                        <form className="contact-form" onSubmit={handleSubmit}>
                            <div className="form-row">
                                <div className="form-group">
                                    <label htmlFor="name">
                                        <User size={16} />
                                        Full Name
                                    </label>
                                    <input
                                        type="text"
                                        id="name"
                                        name="name"
                                        value={formData.name}
                                        onChange={handleChange}
                                        placeholder="Full Name"
                                        required
                                        minLength={2}
                                    />
                                </div>

                                <div className="form-group">
                                    <label htmlFor="email">
                                        <Mail size={16} />
                                        Email Address
                                    </label>
                                    <input
                                        type="email"
                                        id="email"
                                        name="email"
                                        value={formData.email}
                                        onChange={handleChange}
                                        placeholder="Email Address"
                                        required
                                    />
                                </div>
                            </div>

                            <div className="form-group">
                                <label htmlFor="subject">
                                    <Tag size={16} />
                                    Subject
                                </label>
                                <input
                                    type="text"
                                    id="subject"
                                    name="subject"
                                    value={formData.subject}
                                    onChange={handleChange}
                                    placeholder="What's this about?"
                                    required
                                    minLength={3}
                                />
                            </div>

                            <div className="form-group">
                                <label htmlFor="message">
                                    <MessageSquare size={16} />
                                    Message
                                </label>
                                <textarea
                                    id="message"
                                    name="message"
                                    value={formData.message}
                                    onChange={handleChange}
                                    placeholder="Tell me about your project..."
                                    required
                                    minLength={10}
                                    rows={5}
                                />
                            </div>

                            <button
                                type="submit"
                                className="submit-btn"
                                disabled={isSubmitting}
                            >
                                {isSubmitting ? (
                                    <>
                                        <Loader size={18} className="spin" />
                                        Sending...
                                    </>
                                ) : (
                                    <>
                                        <Send size={18} />
                                        Send Message
                                    </>
                                )}
                            </button>
                        </form>

                        {/* Status Message */}
                        {submitStatus && (
                            <motion.div
                                className={`form-message ${submitStatus.type}`}
                                initial={{ opacity: 0, y: -10 }}
                                animate={{ opacity: 1, y: 0 }}
                            >
                                {submitStatus.type === 'success' ? (
                                    <CheckCircle size={20} />
                                ) : (
                                    <AlertCircle size={20} />
                                )}
                                <span>{submitStatus.message}</span>
                            </motion.div>
                        )}
                    </motion.div>
                </motion.div>
            </div>
        </section>
    );
};

export default Contact;

import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Rocket, Mail, Github, Palette, Code, Server } from 'lucide-react';
import { profileData } from '../../data/portfolioData';

// Counter component - defined outside Hero to maintain stable reference
const Counter = ({ target, duration = 2000 }) => {
    const [count, setCount] = useState(0);
    const [hasAnimated, setHasAnimated] = useState(false);

    useEffect(() => {
        if (hasAnimated) return; // Don't re-animate once completed

        let startTime;
        let animationFrameId;

        const animate = (timestamp) => {
            if (!startTime) startTime = timestamp;
            const progress = Math.min((timestamp - startTime) / duration, 1);
            setCount(Math.floor(progress * target));

            if (progress < 1) {
                animationFrameId = requestAnimationFrame(animate);
            } else {
                setHasAnimated(true); // Mark as completed
            }
        };

        const timer = setTimeout(() => {
            animationFrameId = requestAnimationFrame(animate);
        }, 500);

        return () => {
            clearTimeout(timer);
            if (animationFrameId) {
                cancelAnimationFrame(animationFrameId);
            }
        };
    }, [target, duration, hasAnimated]);

    return count;
};

